import { IsNotEmpty, IsNumber, IsString, Min } from "class-validator";
import { ApiProperty } from "@nestjs/swagger";

export class TransferToPublicAccountDto {
  @ApiProperty({
    description:
      "Source account number (obtained from verify-account endpoint)",
    example: "110162904970",
  })
  @IsString()
  @IsNotEmpty()
  accountNumber!: string;

  @ApiProperty({
    description: "Account holder name",
    example: "Jigme Namgyal",
  })
  @IsString()
  @IsNotEmpty()
  accountName!: string;

  @ApiProperty({
    description: "Amount to transfer in BTN",
    example: 150.0,
  })
  @IsNumber()
  @Min(1)
  amount!: number;

  @ApiProperty({
    description: "Transfer description/narration",
    example: "Lottery entry payment",
    required: false,
  })
  @IsString()
  description?: string;

  @ApiProperty({
    description: "CID number of the account holder",
    example: "10605001681",
  })
  @IsString()
  @IsNotEmpty()
  cid!: string;
}
